import{_ as l,o as i,c as r,ai as e}from"./chunks/framework.ampVZV4B.js";const _=JSON.parse('{"title":"02 Prompt 基础：角色/目标/输入输出约束","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-1-llm/02-prompt-basics.md","filePath":"ai/stage-1-llm/02-prompt-basics.md"}'),t={name:"ai/stage-1-llm/02-prompt-basics.md"};function o(s,a,n,p,h,d){return i(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="_02-prompt-基础-角色-目标-输入输出约束" tabindex="-1">02 Prompt 基础：角色/目标/输入输出约束 <a class="header-anchor" href="#_02-prompt-基础-角色-目标-输入输出约束" aria-label="Permalink to “02 Prompt 基础：角色/目标/输入输出约束”">​</a></h1><blockquote><p>目标：把“会问问题”升级成“可复用 Prompt 模板”，让输出稳定、可控。</p></blockquote><h2 id="_1-prompt-的最小结构-背下来" tabindex="-1">1）Prompt 的最小结构（背下来） <a class="header-anchor" href="#_1-prompt-的最小结构-背下来" aria-label="Permalink to “1）Prompt 的最小结构（背下来）”">​</a></h2><ul><li><strong>角色（Role）</strong>：你希望模型扮演谁</li><li><strong>目标（Goal）</strong>：你要它完成什么任务</li><li><strong>输入（Input）</strong>：你提供什么材料</li><li><strong>输出（Output）</strong>：必须用什么格式输出（强约束）</li><li><strong>边界（Constraints）</strong>：不能做什么、不要编造、不要废话</li></ul><h2 id="_2-三套你立刻就能用的模板" tabindex="-1">2）三套你立刻就能用的模板 <a class="header-anchor" href="#_2-三套你立刻就能用的模板" aria-label="Permalink to “2）三套你立刻就能用的模板”">​</a></h2><h3 id="_2-1-面试题生成-基于一段笔记" tabindex="-1">2.1 面试题生成（基于一段笔记） <a class="header-anchor" href="#_2-1-面试题生成-基于一段笔记" aria-label="Permalink to “2.1 面试题生成（基于一段笔记）”">​</a></h3><p>把你笔记贴进去，用这个模板：</p><ul><li>角色：资深 Java 面试官</li><li>目标：生成 10 道面试题 + 标准答案</li><li>输出：Markdown，按“问题/回答/追问/易错点”</li></ul><h3 id="_2-2-学习总结-基于一篇文章" tabindex="-1">2.2 学习总结（基于一篇文章） <a class="header-anchor" href="#_2-2-学习总结-基于一篇文章" aria-label="Permalink to “2.2 学习总结（基于一篇文章）”">​</a></h3><ul><li>角色：技术文档编辑</li><li>目标：提炼 5 点要点 + 2 个例子 + 1 个常见坑</li><li>输出：Markdown，三级标题 + 列表</li></ul><h3 id="_2-3-简历优化-基于一段经历" tabindex="-1">2.3 简历优化（基于一段经历） <a class="header-anchor" href="#_2-3-简历优化-基于一段经历" aria-label="Permalink to “2.3 简历优化（基于一段经历）”">​</a></h3><ul><li>角色：技术面试官 + 简历教练</li><li>目标：改写为“动作 + 技术栈 + 结果”</li><li>输出：3 条可放简历的 bullet</li></ul><h2 id="_3-输出格式强约束-最重要" tabindex="-1">3）输出格式强约束（最重要） <a class="header-anchor" href="#_3-输出格式强约束-最重要" aria-label="Permalink to “3）输出格式强约束（最重要）”">​</a></h2><p>你只要记住一句：<strong>让模型按你要的格式输出，不要让它自由发挥。</strong></p><p>常用约束：</p><ul><li>“必须输出 Markdown”</li><li>“必须包含：标题/步骤/结论”</li><li>“每条不超过 2 行”</li><li>“不要出现‘可能/大概’”</li></ul><h2 id="_4-今日练习-20-分钟" tabindex="-1">4）今日练习（20 分钟） <a class="header-anchor" href="#_4-今日练习-20-分钟" aria-label="Permalink to “4）今日练习（20 分钟）”">​</a></h2><ul><li>选你 <code>docs/</code> 里任意一篇文章</li><li>用“学习总结模板”让模型输出</li><li>你手动微调 Prompt 3 次，观察输出变化</li></ul>',18)])])}const m=l(t,[["render",o]]);export{_ as __pageData,m as default};
